  private static final Int2ObjectMap<String> CACHE = new Int2ObjectOpenHashMap<>();

  static {
    loadConstants(InterfaceId.class);
  }

private static void loadConstants(Class<?> cls) {
    if (!cls.getSimpleName().contains("_100GuideEggsOverlay")) {
      for (Field field : cls.getFields()) {
        if (field.getType() != int.class) continue;
        if (!Modifier.isStatic(field.getModifiers())) continue;
        if (!Modifier.isFinal(field.getModifiers())) continue;
        if (field.getName().equals("_100GUIDE_EGGS_OVERLAY")) continue;

        try {
          field.setAccessible(true);
          int value = field.getInt(null);
          CACHE.put(value, field.getName());
        } catch (Exception e) {
          e.printStackTrace();
        }
      }
    }

    for (Class<?> inner : cls.getDeclaredClasses()) {
      loadConstants(inner);
    }
  }

  public static String toString(int id) {
    return CACHE.getOrDefault(id, "UNK_" + id);
  }
